import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Introduction to Fabric and Modding","description":"A brief introduction to Fabric and modding in Minecraft: Java Edition.","frontmatter":{"title":"Introduction to Fabric and Modding","description":"A brief introduction to Fabric and modding in Minecraft: Java Edition.","authors":["IMB11","itsmiir"],"authors-nogithub":["basil4088"],"files":[]},"headers":[],"relativePath":"1.21.8/develop/getting-started/index.md","filePath":"versions/1.21.8/develop/getting-started/index.md","lastUpdated":1760721669000}`);var a={name:`1.21.8/develop/getting-started/index.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Introduction to Fabric and Modding <a class="header-anchor" href="#h1" aria-label="Permalink to “Introduction to Fabric and Modding”">​</a></h1><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisites”">​</a></h2><p>Before you start, you should have a basic understanding of developing with Java, and an understanding of Object-Oriented Programming (OOP).</p><p>If you are unfamiliar with these concepts, you may want to look into some tutorials on Java and OOP before you start modding, here are some of the resources that you can use to learn Java and OOP:</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Java Tutorials</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Learn Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: Introduction to OOP</a></li></ul><h3 id="terminology" tabindex="-1">Terminology <a class="header-anchor" href="#terminology" aria-label="Permalink to “Terminology”">​</a></h3><p>Before we start, let&#39;s go over some of the terms that you will encounter when modding with Fabric:</p><ul><li><strong>Mod</strong>: A modification to the game, adding new features or changing existing ones.</li><li><strong>Mod Loader</strong>: A tool that loads mods into the game, such as Fabric Loader.</li><li><strong>Mixin</strong>: A tool for modifying the game&#39;s code at runtime - see <a href="https://fabricmc.net/wiki/tutorial:mixin_introduction" target="_blank" rel="noreferrer">Mixin Introduction</a> for more information.</li><li><strong>Gradle</strong>: A build automation tool used to build and compile mods, used by Fabric to build mods.</li><li><strong>Mappings</strong>: A set of mappings that map obfuscated code to human-readable code.</li><li><strong>Obfuscation</strong>: The process of making code difficult to understand, used by Mojang to protect Minecraft&#39;s code.</li><li><strong>Remapping</strong>: The process of mapping obfuscated code to human-readable code.</li></ul><h2 id="what-is-fabric" tabindex="-1">What Is Fabric? <a class="header-anchor" href="#what-is-fabric" aria-label="Permalink to “What Is Fabric?”">​</a></h2><p>Fabric is a lightweight modding toolchain for Minecraft: Java Edition.</p><p>It is designed to be a simple and easy-to-use modding platform. Fabric is a community-driven project, and it is open-source, meaning that anyone can contribute to the project.</p><p>You should be aware of the four main components of Fabric:</p><ul><li><strong>Fabric Loader</strong>: A flexible platform-independent mod loader designed for Minecraft and other games and applications.</li><li><strong>Fabric Loom</strong>: A Gradle plugin enabling developers to easily develop and debug mods.</li><li><strong>Fabric API</strong>: A set of APIs and tools for mod developers to use when creating mods.</li><li><strong>Yarn</strong>: A set of open Minecraft mappings, free for everyone to use under the Creative Commons Zero license.</li></ul><h2 id="why-is-fabric-necessary-to-mod-minecraft" tabindex="-1">Why Is Fabric Necessary to Mod Minecraft? <a class="header-anchor" href="#why-is-fabric-necessary-to-mod-minecraft" aria-label="Permalink to “Why Is Fabric Necessary to Mod Minecraft?”">​</a></h2><blockquote><p>Modding is the process of modifying a game in order to change its behavior or add new features - in the case of Minecraft, this can be anything from adding new items, blocks, or entities, to changing the game&#39;s mechanics or adding new game modes.</p></blockquote><p>Minecraft: Java Edition is obfuscated by Mojang, making modification alone difficult. However, with the help of modding tools like Fabric, modding becomes much easier. There are several mapping systems that can assist in this process.</p><p>Loom remaps the obfuscated code to a human-readable format using these mappings, making it easier for modders to understand and modify the game&#39;s code. Yarn is a popular and excellent mappings choice for this, but other options exist as well. Each mapping project may have its own strengths or focus.</p><p>Loom allows you to easily develop and compile mods against remapped code, and Fabric Loader allows you to load these mods into the game.</p><h2 id="what-does-fabric-api-provide-and-why-is-it-needed" tabindex="-1">What Does Fabric API Provide, and Why Is It Needed? <a class="header-anchor" href="#what-does-fabric-api-provide-and-why-is-it-needed" aria-label="Permalink to “What Does Fabric API Provide, and Why Is It Needed?”">​</a></h2><blockquote><p>Fabric API is a set of APIs and tools for mod developers to use when creating mods.</p></blockquote><p>Fabric API provides a wide set of APIs that build on top of Minecraft&#39;s existing functionality - for example, providing new hooks and events for modders to use, or providing new utilities and tools to make modding easier - such as transitive access wideners and the ability to access internal registries, such as the compostable items registry.</p><p>While Fabric API offers powerful features, some tasks, like basic block registration, can be accomplished without it using the vanilla APIs.</p>`,22)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};